from azq.formam import storage
partial = {'goal_id': 'FINIS_001', 'deliverable_ids': ['DELIV_001']}
fn = getattr(storage, 'normalize_goal_map_record', None) or getattr(storage, 'normalize_goal_map', None)
assert fn is not None, 'goal map normalization helper not found'
result = fn(partial)
for field in ['goal_id', 'deliverable_ids', 'dependency_edges', 'status', 'created', 'notes']:
    assert field in result, f'missing field: {field}'
assert result['goal_id'] == 'FINIS_001'
assert isinstance(result['deliverable_ids'], list)
assert isinstance(result['dependency_edges'], list)
